        {
          "questionText": "What term is used for small-scale electricity production that occurs at the same site where the power is consumed?",
          "answerGuidance": [
            "Micro-generation",
            "Micro generation",
            "Small-scale production at point of use"
          ]
        },
        {
          "questionText": "Which generation method produces electricity by burning organic materials such as wood pellets or plant waste?",
          "answerGuidance": [
            "Biomass",
            "Burning organic materials",
            "Organic fuel generation"
          ]
        }
      ],
      "deeperQuestionText": "How does the implementation of micro-generation differ from traditional large-scale power station generation in the supply chain?",
      "deeperAnswerGuidance": [
        "Electricity is produced at the point of use",
        "It removes the need for long-distance transport from a central station",
        "It functions as a decentralized energy source",
        "The generation happens on-site rather than at a massive remote plant"
      ],
      "hint": "Focus on the specific names of the technologies and the scale of the production."
