    {
      "title": "Transmission Voltages",
      "basicQuestions": [
        {
          "questionText": "What does the abbreviation 'kV' stand for when measuring transmission levels?",
          "answerGuidance": [
            "Kilovolt",
            "Kilo-volt",
            "One thousand volts"
          ]
        },
        {
          "questionText": "What is the highest specific transmission voltage used in the UK grid?",
          "answerGuidance": [
            "400 kV",
            "400,000 Volts",
            "400kV"
          ]
        },
        {
          "questionText": "Besides 400 kV and 275 kV, what is the third standard transmission voltage used in the UK?",
          "answerGuidance": [
            "132 kV",
            "132,000 Volts",
            "132kV"
          ]
        }
      ],
      "deeperQuestionText": "Why is it technically necessary to use extremely high voltages like 275 kV for the national transmission network instead of lower domestic voltages?",
      "deeperAnswerGuidance": [
        "To reduce energy loss during transit",
        "To minimize the amount of power wasted as heat",
        "To move bulk electricity efficiently over long distances",
        "High voltage allows for more efficient transport across the country"
      ],
      "hint": "Recall the three specific UK voltage figures and the physics of moving energy over long distances."
    }
  ]
}

{
  "integrative": {
    "title": "Integrative Close",
    "objective": "Synthesize the identification of a generation method with the application of a correct UK transmission voltage.",
    "retrievalTextLines": [
      "Generation is the starting point where energy sources like gas, nuclear, or renewables are converted to electricity.",
      "To move this electricity over long distances across the UK grid efficiently, we must use specific transmission voltages: 132 kV, 275 kV, or 400 kV.",
      "The choice of voltage ensures minimal energy loss between the generation source and the distant consumer."
    ],
    "questionText": "A large-scale offshore wind farm is being connected to the national grid to provide power to a city 150 miles away. Identify the generation method used in this scenario and name one of the three specific UK transmission voltages that would be used to transport this power over that distance.",
    "answerGuidance": [
      "Generation: Wind; Transmission Voltage: 132 kV",
      "Generation: Wind; Transmission Voltage: 275 kV",
      "Generation: Wind; Transmission Voltage: 400 kV"
    ],
    "hint": "Identify the energy source mentioned (the wind) and then select one of the three 'motorway' voltages we discussed (132, 275, or 400 kV)."
  }
}

